insert into public.entreprises (name, slug, zone, region, city, country, metier, metier_label, color, initials, founded, certifications, address, phone, email, website, description, long_description, adf_url) values
  ('Atelier Louis Del Boca', 'atelier-louis-del-boca', 'France', 'Île-de-France', 'Suresnes', 'France', 'Peinture & Décors', 'Staff · Gypserie · Peinture décorative · Dorure · Maçonnerie', '#6B4F2A', 'DB', '1931', ARRAY['EPV','GMH'], '25 bis, rue Émile Duclaux, 92150 Suresnes', '+33 (0)1 41 38 17 17', 'contact@delboca.fr', 'http://www.delboca.fr', 'Depuis 1931, l''Atelier Louis Del Boca perpétue les grandes traditions françaises du décor intérieur : staff, gypserie, peinture décorative, dorure à la feuille et maçonnerie de haute qualité pour les palaces et monuments historiques.', 'Fondé en 1931, l''Atelier Louis Del Boca compte parmi les maisons de référence pour la restauration et la création de décors intérieurs d''exception. Ses compagnons staffeurs, peintres décorateurs et doreurs maîtrisent les techniques héritées du XIXe siècle, au service des grands palaces parisiens, des ambassades et des chantiers MH les plus prestigieux — Château de Versailles, Hôtel de Crillon, Opéra Garnier.', 'https://ateliersdefrance.com/entreprises/atelier-louis-del-boca/'),
  ('H. Chevalier', 'h-chevalier', 'France', 'Île-de-France', 'Suresnes', 'France', 'Pierre & Maçonnerie', 'Taille de pierre · Maçonnerie · Gros œuvre · Restauration bâti ancien', '#3A5C4A', 'HC', '1946', ARRAY['EPV','GMH'], '26, rue Henri Regnault, 92150 Suresnes Cedex', '+33 (0)1 45 06 83 33', 'contact@hchevalier.com', 'http://www.hchevalier.com', 'Créée en 1946, H. Chevalier est la référence du groupe pour la restauration du bâti ancien et des monuments historiques : taille de pierre, maçonnerie, gros œuvre sur les chantiers les plus exigeants.', 'H. Chevalier dispose de son propre bureau d''appareilleurs et d''un atelier de taille de pierre qui lui permettent de maîtriser en totalité les interventions les plus complexes. Ses équipes ont œuvré sur les façades classées du Château de Versailles, de l''Hôtel de la Marine, du Palais de l''Élysée et de nombreux hôtels particuliers parisiens inscrits aux Monuments Historiques.', 'https://ateliersdefrance.com/entreprises/h-chevalier/'),
  ('Rémy Garnier', 'remy-garnier', 'France', 'Paris', 'Paris', 'France', 'Métal', 'Serrurerie décorative · Quincaillerie d''art · Ciselure · Dorure sur bronze', '#2A3F6B', 'RG', '1832', ARRAY['EPV','GMH'], '30 bis, Boulevard de la Bastille, 75012 Paris', '+33 (0)1 43 43 84 85', 'r.garnier@remygarnier.fr', 'http://www.remygarnier.fr', 'Depuis 1832, Rémy Garnier est l''une des maisons de serrurerie d''art les plus anciennes du monde — des milliers de références de quincaillerie, poignées, crémones et accessoires en bronze ciselé et doré.', 'Fondée en 1832, la maison Rémy Garnier détient l''une des plus vastes collections de quincaillerie d''art au monde. Poignées, serrures, crémones, espagnolettes et accessoires en bronze sont fabriqués et finis à la main dans ses ateliers parisiens. Ses réalisations ornent les plus grandes demeures, palaces et résidences officielles — de l''Hôtel Peninsula Paris à des palais du Moyen-Orient.', 'https://ateliersdefrance.com/entreprises/remy-garnier/'),
  ('6ixtes', '6ixtes', 'France', 'France', null, 'France', 'Lots techniques', 'Appareillages électriques haut de gamme en laiton', '#4A3A2A', '6X', null, '{}', null, null, null, null, 'Fabrication d''appareillages électriques haut de gamme en laiton.', null, 'https://ateliersdefrance.com/entreprises/6ixtes/'),
