insert into public.knowledge_base (title, type, description, source) values
  ('Restauration pierre de taille en site occupé : Hôtel de la Marine, Paris', 'rex', 'Intervention sur façades classées MH place de la Concorde avec bâtiment en activité. Protocoles d''échafaudage et de protection adaptés, taille de pierre en atelier avant pose. Joints à la chaux hydraulique naturelle conforme aux prescriptions de l''Architecte en Chef des Monuments Historiques.', 'H. Chevalier'),
  ('Château de Versailles : logistique d''un chantier MH multi-corps d''état', 'rex', 'Coordination de plusieurs corps de métier (taille de pierre, maçonnerie ancienne, enduits à la chaux, métallerie) sur les façades et toitures du château. Rôle central du bureau d''appareilleurs H. Chevalier pour garantir la conformité des tailles, le respect des modénatures et la qualité des joints à la chaux. Référence de chantier emblématique pour l''ensemble du groupe ADF.', 'H. Chevalier'),
  ('Techniques de staff XIXe siècle : corniches, rosaces et ornements à la française', 'technique', 'Méthodes de tirage de corniches au calibre, moulage de rosaces et ornements en plâtre pur ou armé. Préconisations pour assemblage sur faux-plafond existant et traitement des supports anciens fragilisés. Techniques utilisées à l''Opéra Garnier, à l''Hôtel de Crillon et dans les galeries du Louvre.', 'Atelier Louis Del Boca'),
  ('Dorure à la feuille sur staff : préparation du support et choix des assiettes', 'bonnes_pratiques', 'Les supports en staff nécessitent une isolation de surface avant pose de l''assiette. Comparatif des assiettes (mixtion huile vs assiette à l''eau), durées de séchage et compatibilité avec l''humidité résiduelle du plâtre. Retours issus des chantiers Hôtel de Crillon et Bureau Ovale de l''Élysée.', 'Atelier Louis Del Boca'),
  ('Hôtel Peninsula Paris : serrurerie décorative coordonnée sur 200 chambres', 'rex', 'Fourniture et pose de l''ensemble de la quincaillerie d''art — poignées, serrures, espagnolettes, accessoires de salle de bain — dans un style Art Déco unifié. Adaptation des finitions (dorure 24 carats, nickel brossé, patine bronze vieilli) aux contraintes d''un palace 5 étoiles en exploitation.', 'Rémy Garnier'),
  ('Ciselure sur bronze : finition à la main et critères de réception qualité', 'bonnes_pratiques', 'La ciselure est réalisée après fonte et dégraissage, avant patine ou dorure. Outillage traditionnel (ciselets, brunissoirs) et séquençage des opérations pour éviter les reprises. Critères de réception qualité applicables sur chantier palace : lumière rasante, test au doigt, contrôle des angles vifs.', 'Rémy Garnier'),
  ('Restauration de l''Église Saint-Laurent (Marseille) : calcaires provençaux et sel marin', 'rex', 'Spécificité des calcaires provençaux : taille aisée mais nécessitant des joints à la chaux aérienne faiblement hydraulique. Retour d''expérience sur la gestion des pathologies liées au sel marin et aux cycles de cristallisation en façade. Protocole de consolidation et d''hydrofugation adapté au contexte climatique méditerranéen.', 'Vivian & Cie'),
  ('Cuir de Cordoue : technique de réalisation et restauration pour boiseries de prestige', 'technique', 'Histoire et procédé du cuir de Cordoue gaufré et doré — technique espagnole du XVIe siècle remise en œuvre par l''Atelier Mériguet-Carrère. Méthode de restauration des panneaux existants (consolidation, nettoyage, retouches dorure) et fabrication à l''identique. Chantiers de référence : Château de Fontainebleau, hôtels particuliers du Marais.', 'Atelier Mériguet-Carrère'),
  ('Opéra Garnier : coordination interentreprises sur un chantier emblématique du patrimoine', 'rex', 'Retour d''expérience sur l''organisation d''un chantier faisant intervenir simultanément des staffeurs, des doreurs, des peintres décorateurs et des restaurateurs d''œuvres d''art. Enjeux de phasage, de protection des décors existants et de communication avec la maîtrise d''ouvrage (Opéra de Paris / CMN). Exemple de coordination réussie dans l''écosystème ADF.', 'Atelier Louis Del Boca'),
  ('Peinture décorative et trompe-l''œil : techniques et supports contemporains', 'technique', 'Panorama des techniques de peinture décorative maîtrisées dans le groupe : badigeon à la chaux, lavis à l''aquarelle, peinture à l''huile sur enduit, trompe-l''œil architecturaux. Compatibilité avec les supports contemporains (Fermacell, Knauf) et réversibilité des interventions sur patrimoine classé. Savoir-faire distincts de Hare & Humphreys (UK) et de l''Atelier Mériguet-Carrère (France).', 'Atelier Mériguet-Carrère');
